update orders
status = #{status}, checkout_time = #{checkoutTime}, pay_method = #{payMethod}, pay_status = #{payStatus}, amount = #{amount}, remark = #{remark}, user_name = #{userName}, cancel_reason = #{cancelReason}, rejection_reason = #{rejectionReason}, cancel_time = #{cancelTime}, tableware_number = #{tablewareNumber}, tableware_status = #{tablewareStatus},
where id = #{id}

mapper.select:
select id, number, status, user_id, order_time, checkout_time,
       pay_method, pay_status, amount, remark, user_name,
       cancel_reason, rejection_reason, cancel_time
from orders

    and number = #{number}
    and status = #{status}
    and user_id = #{userId}
    and order_time >= #{beginTime}
    and order_time <= #{endTime}

order by order_time desc

select id, number, status, user_id, order_time, checkout_time, pay_method, pay_status, amount, remark, user_name, cancel_reason, rejection_reason, cancel_time from orders
and user_id = #{userId} and status in (1, 2, 3, 4) and status = #{status}
order by order_time desc
